// Extract Vapi tool call payload
const body = $input.item.json.body || $input.item.json;

// Vapi sends tool calls inside message.toolCallList
const message = body.message || {};
const toolCallList = message.toolCallList || [];
const toolCall = toolCallList[0] || {};

// Extract key fields
const toolCallId = toolCall.id || '';
const toolName = toolCall.function?.name || '';
const toolArgs = toolCall.function?.arguments || {};

// Get the user's spoken text (query)
// Vapi passes the user message in the transcript or as a tool argument
const userQuery = toolArgs.query
  || toolArgs.message
  || toolArgs.text
  || message.transcript
  || '';

// Session ID from call ID for memory
const callId = body.call?.id
  || message.call?.id
  || body.callSid
  || 'default-session';

return {
  json: {
    toolCallId,
    toolName,
    toolArgs,
    userQuery,
    callId,
    rawBody: body
  }
};

