// Build the Vapi-required response format
// Vapi REQUIRES: { results: [{ toolCallId, result }] }
// The toolCallId MUST match exactly what was sent in the tool call

const toolCallId = $('Extract Vapi Payload').item.json.toolCallId;
const agentOutput = $input.item.json.output;

// agentOutput is the parsed structured output from the AI agent
let responseText = '';
let category = 'other';
let escalate = false;
let resolved = false;

if (typeof agentOutput === 'object' && agentOutput !== null) {
  responseText = agentOutput.response || 'I apologize, I could not process your request. Please try again.';
  category = agentOutput.category || 'other';
  escalate = agentOutput.escalate || false;
  resolved = agentOutput.resolved || false;
} else {
  responseText = String(agentOutput || 'I apologize, I could not process your request.');
}

// Result must be a string for Vapi to speak it
const resultPayload = JSON.stringify({
  response: responseText,
  category: category,
  escalate: escalate,
  resolved: resolved
});

return {
  json: {
    results: [
      {
        toolCallId: toolCallId,
        result: resultPayload
      }
    ],
    // Also expose fields for downstream logging
    _meta: {
      responseText,
      category,
      escalate,
      resolved,
      callId: $('Extract Vapi Payload').item.json.callId
    }
  }
};

// Process Vapi end-of-call report
// Vapi sends this after every call ends with full transcript + summary

const body = $input.item.json.body || $input.item.json;
const message = body.message || {};

const callId = body.call?.id || message.call?.id || 'unknown';
const callDuration = body.call?.endedAt
  ? Math.round((new Date(body.call.endedAt) - new Date(body.call.startedAt)) / 1000)
  : 0;

const transcript = message.transcript || body.transcript || '';
const summary = message.summary || body.summary || '';
const endedReason = body.call?.endedReason || message.endedReason || 'unknown';

// Collect structured data
const recordedAt = new Date().toISOString();

return {
  json: {
    callId,
    callDuration,
    transcript,
    summary,
    endedReason,
    recordedAt,
    category: 'unknown',
    escalate: false,
    resolved: false,
    rawPayload: body
  }
};

